import { ToastService } from '../services/toast.service';
import { ConfirmService } from '../services/confirm.service';
import { Component, OnInit } from '@angular/core';
import { FormBuilder, FormGroup, Validators, FormsModule, ReactiveFormsModule } from '@angular/forms';
import { CommonModule } from '@angular/common';
import jsPDF from 'jspdf';
import { InterrogatoireService } from '../services/interrogatoire.service';
import { EmployeService } from '../services/employe.service';

@Component({
  selector: 'app-interrogatoire',
  standalone: true,
  imports: [CommonModule, FormsModule, ReactiveFormsModule],
  templateUrl: './interrogatoire.component.html',
  styleUrls: ['./interrogatoire.component.css']
})
export class InterrogatoireComponent implements OnInit {
  form!: FormGroup;
  employes: any[] = [];
  interrogatoires: any[] = [];
  nomEmploye: string = '';
  zoneEmploye: string = '';
  currentEditingId: number | null = null;

  searchMatricule: string = '';
searchZone: string = '';
searchDate: string = '';
searchType: string = '';
filteredInterrogatoires: any[] = [];

  constructor(private fb: FormBuilder,
    private interrogatoireService: InterrogatoireService,
    private employeService: EmployeService, private toastService: ToastService, private confirmService: ConfirmService) {}

  ngOnInit(): void {
    this.form = this.fb.group({
      date: [null, Validators.required],
      matricule: ['', Validators.required],
      sujet: ['', Validators.required],
      reponseEmploye: ['', Validators.required],
      punitionProposee: ['', Validators.required],
      nombreJours: [null],
      dateConseilDiscipline: [null]
    });

    this.loadEmployes();
    this.loadInterrogatoires();
    this.form.get('matricule')?.valueChanges.subscribe(() => {
      this.remplirNomEtZone();
    });
  }

  loadEmployes() {
    this.employeService.getAllEmployes().subscribe(data => {
      this.employes = data;
    });
  }
  loadInterrogatoires() {
    this.interrogatoireService.getAll().subscribe(data => {
      // Trier du plus récent au plus ancien (par id ici)
      this.interrogatoires = data.sort((a, b) => b.id - a.id);
      this.applyFilter();
    });
  }
  resetFilter() {
  this.searchMatricule = '';
  this.searchZone = '';
  this.searchType = '';
  this.applyFilter();
}

applyFilter() {
  this.filteredInterrogatoires = this.interrogatoires.filter(i => {
    const matricule = i.employe?.matricule?.toLowerCase() || '';
    const zone = i.employe?.zone?.toLowerCase() || '';
    const sujet = i.sujet?.toLowerCase() || '';

    const matchMatricule = this.searchMatricule.trim() === '' || matricule.includes(this.searchMatricule.toLowerCase().trim());
    const matchZone = this.searchZone.trim() === '' || zone.includes(this.searchZone.toLowerCase().trim());
    const matchType = this.searchType.trim() === '' || sujet.includes(this.searchType.toLowerCase().trim());

    return matchMatricule && matchZone && matchType;
  });
}


  remplirNomEtZone(): void {
    const matricule = this.form.get('matricule')?.value?.trim().toLowerCase();
    const emp = this.employes.find(e => e.matricule?.toLowerCase() === matricule);
    if (emp) {
      this.nomEmploye = emp.fullname || '';
      this.zoneEmploye = emp.zone || '';
    } else {
      this.nomEmploye = '';
      this.zoneEmploye = '';
    }
  }

  isSuspensionTemporaire(): boolean {
    return this.form.get('punitionProposee')?.value === 'Suspension temporaire du travail';
  }

  isConseilDiscipline(): boolean {
    return this.form.get('punitionProposee')?.value === 'Saisine du conseil de discipline';
  }

onSubmit() {
  if (this.form.valid) {
    const employe = this.employes.find(e => e.matricule?.toLowerCase() === this.form.value.matricule?.toLowerCase());
    const payload = {
      ...this.form.value,
      employe: { id: employe?.id }
    };

    console.log('Payload envoyé:', payload);
    console.log('currentEditingId:', this.currentEditingId);

    if (this.currentEditingId !== null && this.currentEditingId !== undefined) {
      this.interrogatoireService.update(this.currentEditingId, payload).subscribe({
        next: () => {
          this.toastService.show('Interrogatoire modifié avec succès', 'success');
          this.currentEditingId = null;
          this.resetForm();
          this.loadInterrogatoires();
        },
        error: (err) => {
          console.error('Erreur lors de la modification:', err);
          this.toastService.show('Erreur lors de la modification', 'error');
        }
      });
    } else {
      this.interrogatoireService.add(payload).subscribe(() => {
        this.toastService.show('Interrogatoire enregistré avec succès', 'success');
        this.resetForm();
        this.loadInterrogatoires();
      });
    }
  }
}


editInterrogatoire(i: any) {
  console.log('Interrogatoire à éditer:', i);
  this.form.patchValue({
    matricule: i.employe?.matricule || '',
    date: i.date ? new Date(i.date) : null,
    sujet: i.sujet || '',
    reponseEmploye: i.reponseEmploye || '',
    punitionProposee: i.punitionProposee || '',
    nombreJours: i.nombreJours != null ? i.nombreJours : null,
    dateConseilDiscipline: i.dateConseilDiscipline ? new Date(i.dateConseilDiscipline) : null
  });
  this.remplirNomEtZone();
  this.currentEditingId = i.id;
}



  deleteInterrogatoire(id: number) {
    this.confirmService.confirm('Voulez-vous vraiment supprimer cet interrogatoire ?').then(res => {
      if (res) {
        this.interrogatoireService.delete(id).subscribe(() => {
          this.toastService.show('Interrogatoire supprimé', 'warning');
          this.loadInterrogatoires();
        });
      }
    });
  }

  generatePdfFromInterrogatoire(i: any) {
  const doc = new jsPDF();
  let y = 10;
  const lineHeight = 10;
  const pageWidth = doc.internal.pageSize.getWidth();
  const margin = 10;
  const maxWidth = pageWidth - 2 * margin;

  // --- Ajouter le logo ---
  // Remplace ici par ta propre image en base64 ou url convertie en base64
  // Exemple d'une image PNG en base64 (petit carré rouge en 50x50)
 const logoBase64 = 'data:image/png;base64,'; // ton logo ici
  doc.addImage(logoBase64, 'JPEG', 15, 10, 30, 20);

  // === Titre ===
  doc.setFontSize(18);
  doc.setTextColor(40);
  const logoWidth = 40;
  const logoHeight = 40;

  // Titre à droite du logo
  doc.setFontSize(18);
  doc.text("Interrogatoire disciplinaire", margin + logoWidth + 10, y + 15);

  y += logoHeight + 10;

  // --- Date de l'interrogatoire (formatée) ---
  const dateInterro = i.date ? new Date(i.date).toLocaleDateString('fr-FR') : 'Non définie';
  doc.setFontSize(12);
  doc.text(`Date de l’interrogatoire : ${dateInterro}`, margin, y);
  y += lineHeight;

  // --- Autres infos ---
  doc.text(`Employé : ${i.employe?.fullname}`, margin, y);
  y += lineHeight;

  doc.text(`Zone : ${i.employe?.zone}`, margin, y);
  y += lineHeight;

  doc.text(`Sujet : ${i.sujet}`, margin, y);
  y += lineHeight;

  // Réponse avec retour à la ligne automatique
  const reponse = `Réponse : ${i.reponseEmploye}`;
  const reponseLines = doc.splitTextToSize(reponse, maxWidth);
  doc.text(reponseLines, margin, y);
  y += lineHeight * reponseLines.length;

  doc.text(`Punition proposée : ${i.punitionProposee}`, margin, y);
  y += lineHeight;

  if (i.punitionProposee === 'Suspension temporaire du travail') {
    const texte = `Suspension temporaire pour ${i.nombreJours} jour(s).`;
    const suspensionLines = doc.splitTextToSize(texte, maxWidth);
    doc.text(suspensionLines, margin, y);
    y += lineHeight * suspensionLines.length;
  }

  if (i.punitionProposee === 'Saisine du conseil de discipline') {
    const dateConseil = i.dateConseilDiscipline ? new Date(i.dateConseilDiscipline).toLocaleDateString('fr-FR') : 'Non définie';
    const texte = `Saisine du conseil de discipline avec suspension de travail pour une durée de ${i.nombreJours} jour(s) et fixation de la date du conseil au ${dateConseil}.`;
    const conseilLines = doc.splitTextToSize(texte, maxWidth);
    doc.text(conseilLines, margin, y);
    y += lineHeight * conseilLines.length;
  }

  doc.save(`interrogatoire_${i.employe?.fullname}.pdf`);
}


  resetForm() {
    this.form.reset();
    this.nomEmploye = '';
    this.zoneEmploye = '';
    this.currentEditingId = null;
  }
}
